import{_ as e,o as r,c as a,a2 as d}from"./chunks/framework.c3r8iWL8.js";const p=JSON.parse('{"title":"Guide: Linters & Static Analysis","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"guides/static-analysis-linting.md","filePath":"guides/static-analysis-linting.md","lastUpdated":1782929962000}'),s={name:"guides/static-analysis-linting.md"};function o(n,t,i,l,c,h){return r(),a("div",null,[...t[0]||(t[0]=[d(`<h1 id="guide-linters-static-analysis" tabindex="-1">Guide: Linters &amp; Static Analysis <a class="header-anchor" href="#guide-linters-static-analysis" aria-label="Permalink to &quot;Guide: Linters &amp; Static Analysis&quot;">​</a></h1><p><strong>Decision:</strong> Which classic code-quality and security validators to run, where to run them, and how they complement AI-generated code.</p><p>Related: <a href="./../qa-guardrails.html">qa-guardrails.md</a> · <a href="./ai-guardrails-security.html">ai-guardrails-security.md</a> · <a href="./../developer-workflow.html">developer-workflow.md</a> · <a href="./../sops/SOP-005-pr-review.html">SOP-005</a></p><hr><h2 id="why-this-matters-with-ai-assisted-development" tabindex="-1">Why this matters with AI-assisted development <a class="header-anchor" href="#why-this-matters-with-ai-assisted-development" aria-label="Permalink to &quot;Why this matters with AI-assisted development&quot;">​</a></h2><p>AI tools generate code quickly but do not guarantee:</p><ul><li>Consistent style or idioms</li><li>Type correctness</li><li>Security patterns (SQL injection, hardcoded secrets)</li><li>Dependency CVEs</li><li>Valid OpenAPI/spec syntax</li></ul><p><strong>Classic linters and static analyzers</strong> are the non-negotiable baseline. They are deterministic, auditable, and should run <strong>before</strong> AI PR review and human merge — locally, at commit, and in CI.</p><hr><h2 id="where-tools-run-recommended-stack" tabindex="-1">Where tools run (recommended stack) <a class="header-anchor" href="#where-tools-run-recommended-stack" aria-label="Permalink to &quot;Where tools run (recommended stack)&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Editor (on save)  →  pre-commit (commit)  →  CI (PR + main)  →  CD (release image scan)</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Stage</th><th>Purpose</th><th>Fail fast?</th></tr></thead><tbody><tr><td><strong>Editor / IDE</strong></td><td>Lint, format, typecheck on save</td><td>Developer feedback</td></tr><tr><td><strong>pre-commit</strong></td><td>Same checks + secrets before push</td><td>Block commit</td></tr><tr><td><strong>CI</strong></td><td>Full suite on clean runner</td><td>Block merge</td></tr><tr><td><strong>CD</strong></td><td>Container/IaC scan on artifact</td><td>Block deploy</td></tr></tbody></table><p><strong>Pitfall:</strong> CI-only checks → developers push broken code repeatedly and waste pipeline time. Mirror critical checks in pre-commit.</p><hr><h2 id="tool-categories" tabindex="-1">Tool categories <a class="header-anchor" href="#tool-categories" aria-label="Permalink to &quot;Tool categories&quot;">​</a></h2><h3 id="_1-linters-style-bugs-complexity" tabindex="-1">1. Linters (style, bugs, complexity) <a class="header-anchor" href="#_1-linters-style-bugs-complexity" aria-label="Permalink to &quot;1. Linters (style, bugs, complexity)&quot;">​</a></h3><p>Catch stylistic drift and common bug patterns. Essential when AI output varies in style.</p><table tabindex="0"><thead><tr><th>Language</th><th>Common tools</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>JavaScript / TypeScript</strong></td><td>ESLint, Biome</td><td>ESLint: huge ecosystem; Biome: fast all-in-one</td><td>Two formatters if ESLint + Prettier overlap</td></tr><tr><td><strong>Python</strong></td><td>Ruff, Pylint, Flake8</td><td>Ruff: fast; replaces many Flake8 plugins</td><td>Pylint slower; strict defaults annoy teams</td></tr><tr><td><strong>Go</strong></td><td>golangci-lint (meta-linter)</td><td>Single entry; many linters</td><td>Config complexity</td></tr><tr><td><strong>Java / Kotlin</strong></td><td>Checkstyle, SpotBugs, detekt</td><td>Mature in enterprise Java</td><td>Gradle/Maven setup overhead</td></tr><tr><td><strong>Rust</strong></td><td>Clippy</td><td>Idiomatic Rust enforcement</td><td>—</td></tr><tr><td><strong>Shell / YAML / Markdown</strong></td><td>ShellCheck, yamllint, markdownlint</td><td>CI/config hygiene</td><td>Noise on generated YAML</td></tr></tbody></table><p><strong>Suggested starting point:</strong> One linter per language; share config in repo root; extend gradually.</p><hr><h3 id="_2-formatters-auto-fix-layout" tabindex="-1">2. Formatters (auto-fix layout) <a class="header-anchor" href="#_2-formatters-auto-fix-layout" aria-label="Permalink to &quot;2. Formatters (auto-fix layout)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool</th><th>Languages</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>Prettier</strong></td><td>JS/TS/CSS/JSON/MD</td><td>De facto standard</td><td>Less control over style debates</td></tr><tr><td><strong>Biome</strong></td><td>JS/TS</td><td>Lint + format in one</td><td>Newer ecosystem</td></tr><tr><td><strong>Black</strong></td><td>Python</td><td>Zero config</td><td>Conflicts with older Pylint rules</td></tr><tr><td><strong>Ruff format</strong></td><td>Python</td><td>Black-compatible; fast</td><td>Teams on Black already may duplicate</td></tr><tr><td><strong>gofmt / goimports</strong></td><td>Go</td><td>Built-in culture</td><td>—</td></tr><tr><td><strong>rustfmt</strong></td><td>Rust</td><td>Standard</td><td>—</td></tr></tbody></table><p><strong>Pitfall:</strong> Formatter wars in PRs. Pick one; run in CI; AI agents should use same config via <code>.editorconfig</code> + checked-in config files.</p><hr><h3 id="_3-type-checkers-static-typing" tabindex="-1">3. Type checkers (static typing) <a class="header-anchor" href="#_3-type-checkers-static-typing" aria-label="Permalink to &quot;3. Type checkers (static typing)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool</th><th>Languages</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>TypeScript (<code>tsc</code>)</strong></td><td>TS</td><td>Catches API shape errors early</td><td><code>any</code> bypasses checks</td></tr><tr><td><strong>mypy / pyright</strong></td><td>Python</td><td>Catches AI wrong-type assignments</td><td>Gradual typing migration pain</td></tr><tr><td><strong>Java compiler</strong></td><td>Java</td><td>Strong typing built-in</td><td>—</td></tr></tbody></table><p><strong>With AI:</strong> Require typed public APIs; AI often omits types or uses overly broad types. Typecheck in CI catches this before runtime.</p><hr><h3 id="_4-sast-security-static-analysis" tabindex="-1">4. SAST (security static analysis) <a class="header-anchor" href="#_4-sast-security-static-analysis" aria-label="Permalink to &quot;4. SAST (security static analysis)&quot;">​</a></h3><p>Find vulnerability patterns in source code.</p><table tabindex="0"><thead><tr><th>Tool</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>Semgrep</strong></td><td>Custom rules; fast; good for CI</td><td>Rule tuning needed</td></tr><tr><td><strong>CodeQL (GitHub)</strong></td><td>Deep analysis; query language</td><td>Heavier; GitHub-centric</td></tr><tr><td><strong>SonarQube</strong></td><td>Dashboard; quality gate history</td><td>Server to operate</td></tr><tr><td><strong>Checkmarx / Veracode</strong></td><td>Enterprise compliance</td><td>Cost; slower feedback</td></tr><tr><td><strong>Bandit</strong></td><td>Python-focused</td><td>Python only</td></tr></tbody></table><p><strong>Suggested starting point:</strong> Semgrep OSS rules + language-specific (Bandit for Python) in CI; block Critical/High.</p><p><strong>Pitfall:</strong> AI generates plausible but insecure code (string SQL, path traversal). SAST catches patterns humans miss in fast review.</p><hr><h3 id="_5-sca-software-composition-analysis" tabindex="-1">5. SCA (software composition analysis) <a class="header-anchor" href="#_5-sca-software-composition-analysis" aria-label="Permalink to &quot;5. SCA (software composition analysis)&quot;">​</a></h3><p>Scan dependencies for known CVEs and license issues.</p><table tabindex="0"><thead><tr><th>Tool</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>Dependabot</strong></td><td>GitHub-native; PRs for bumps</td><td>GitHub-only</td></tr><tr><td><strong>Renovate</strong></td><td>Multi-platform; flexible</td><td>Config learning curve</td></tr><tr><td><strong>Snyk</strong></td><td>Dev-friendly; container too</td><td>Cost at scale</td></tr><tr><td><strong>AWS Inspector</strong></td><td>AWS-native for ECR/Lambda deps</td><td>AWS-centric</td></tr><tr><td><strong>OWASP Dependency-Check</strong></td><td>Open source</td><td>False positives</td></tr></tbody></table><p><strong>Pitfall:</strong> AI adds dependencies casually (<code>import obscure-lib</code>). SCA must run on every PR that touches lockfiles.</p><hr><h3 id="_6-secret-scanners" tabindex="-1">6. Secret scanners <a class="header-anchor" href="#_6-secret-scanners" aria-label="Permalink to &quot;6. Secret scanners&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>gitleaks</strong></td><td>Fast; pre-commit hook</td><td>False positives in tests</td></tr><tr><td><strong>GitGuardian</strong></td><td>Enterprise policy</td><td>Cost</td></tr><tr><td><strong>TruffleHog</strong></td><td>Deep history scan</td><td>Slower</td></tr><tr><td><strong>detect-secrets</strong></td><td>Baseline allowlist</td><td>Maintenance of baseline</td></tr></tbody></table><p><strong>With AI:</strong> Models occasionally emit fake or real-looking keys. Block merge on any new secret pattern; never rely on human eyeballing diffs.</p><hr><h3 id="_7-license-compliance" tabindex="-1">7. License compliance <a class="header-anchor" href="#_7-license-compliance" aria-label="Permalink to &quot;7. License compliance&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>FOSSA</strong></td><td>Policy dashboards</td><td>Cost</td></tr><tr><td><strong>Snyk License</strong></td><td>Bundled with SCA</td><td>—</td></tr><tr><td><strong>license-checker (npm)</strong></td><td>Simple npm</td><td>npm only</td></tr><tr><td><strong>pip-licenses / go-licenses</strong></td><td>CLI per ecosystem</td><td>Manual aggregation</td></tr></tbody></table><p><strong>Pitfall:</strong> AI imports GPL library into proprietary service. Automate license scan on dependency changes.</p><hr><h3 id="_8-iac-config-validators" tabindex="-1">8. IaC &amp; config validators <a class="header-anchor" href="#_8-iac-config-validators" aria-label="Permalink to &quot;8. IaC &amp; config validators&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool</th><th>Targets</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>Checkov</strong></td><td>Terraform, CloudFormation, K8s</td><td>Broad</td><td>Verbose defaults</td></tr><tr><td><strong>tfsec / Trivy (IaC)</strong></td><td>Terraform</td><td>Fast</td><td>Overlap with Checkov</td></tr><tr><td><strong>cfn-lint</strong></td><td>CloudFormation</td><td>AWS-native</td><td>CFN only</td></tr><tr><td><strong>CDK Nag</strong></td><td>AWS CDK</td><td>Aspect-based rules</td><td>CDK only</td></tr><tr><td><strong>kubeconform / kube-linter</strong></td><td>Kubernetes manifests</td><td>K8s hygiene</td><td>—</td></tr><tr><td><strong>OPA / Conftest</strong></td><td>Custom policy</td><td>Links to ADRs</td><td>Write policies</td></tr></tbody></table><p><strong>Suggested starting point:</strong> Checkov or CDK Nag for AWS teams; Conftest for org-specific rules referencing ADRs.</p><hr><h3 id="_9-container-image-scanners" tabindex="-1">9. Container &amp; image scanners <a class="header-anchor" href="#_9-container-image-scanners" aria-label="Permalink to &quot;9. Container &amp; image scanners&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>Trivy</strong></td><td>OS + app CVEs; IaC</td><td>—</td></tr><tr><td><strong>ECR enhanced scanning</strong></td><td>AWS-native</td><td>AWS-only</td></tr><tr><td><strong>Grype / Syft</strong></td><td>SBOM + scan</td><td>Extra tooling</td></tr><tr><td><strong>Snyk Container</strong></td><td>Unified with SCA</td><td>Cost</td></tr></tbody></table><p>Run at <strong>image build</strong> and block Critical CVEs on deploy (tier-dependent exceptions via <a href="./../sops/SOP-012-exception-handling.html">SOP-012</a>).</p><hr><h3 id="_10-api-spec-validators" tabindex="-1">10. API &amp; spec validators <a class="header-anchor" href="#_10-api-spec-validators" aria-label="Permalink to &quot;10. API &amp; spec validators&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool</th><th>Purpose</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>Spectral</strong></td><td>OpenAPI/AsyncAPI lint</td><td>Custom rules (e.g. require <code>x-adr</code>)</td><td>Rule authoring</td></tr><tr><td><strong>openapi-diff</strong></td><td>Breaking change detection</td><td>Protects consumers</td><td>Needs baseline spec</td></tr><tr><td><strong>buf</strong></td><td>Protobuf breaking changes</td><td>Strong for gRPC</td><td>Not for OpenAPI-only shops</td></tr><tr><td><strong>Schemathesis</strong></td><td>Property-based API testing</td><td>Finds spec violations</td><td>Not a linter — pairs with spec</td></tr></tbody></table><p><strong>With AI:</strong> AI drafts OpenAPI with subtle errors. Spectral in spec PR CI; Schemathesis in service CI.</p><hr><h3 id="_11-orchestration-pre-commit" tabindex="-1">11. Orchestration: pre-commit <a class="header-anchor" href="#_11-orchestration-pre-commit" aria-label="Permalink to &quot;11. Orchestration: pre-commit&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Approach</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>pre-commit framework</strong></td><td>Language-agnostic hooks; shared config</td><td>Developers must install hooks</td></tr><tr><td><strong>Husky + lint-staged</strong></td><td>JS ecosystem standard</td><td>JS-centric</td></tr><tr><td><strong>CI only</strong></td><td>No local setup</td><td>Slow feedback loop</td></tr></tbody></table><p><strong>Suggested hooks (minimum):</strong> secrets (gitleaks) → formatter → linter → typecheck (if applicable).</p><p>Example hook categories for <strong>your</strong> project (implement in your repo, not here):</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gitleaks protect</span></span>
<span class="line"><span>ruff check / eslint</span></span>
<span class="line"><span>ruff format --check / prettier --check</span></span>
<span class="line"><span>mypy / tsc --noEmit</span></span>
<span class="line"><span>spectral lint specs/openapi/*.yaml   # on spec changes only</span></span></code></pre></div><hr><h2 id="ci-gate-matrix-reference" tabindex="-1">CI gate matrix (reference) <a class="header-anchor" href="#ci-gate-matrix-reference" aria-label="Permalink to &quot;CI gate matrix (reference)&quot;">​</a></h2><p>Adapt severity by service tier (<a href="./../GOVERNANCE.html">GOVERNANCE.md</a>).</p><table tabindex="0"><thead><tr><th>Check</th><th>Local / pre-commit</th><th>CI merge gate</th><th>Typical block threshold</th></tr></thead><tbody><tr><td>Formatter</td><td>Yes</td><td>Yes</td><td>Any diff</td></tr><tr><td>Linter</td><td>Yes</td><td>Yes</td><td>Errors (warnings advisory)</td></tr><tr><td>Typecheck</td><td>Yes</td><td>Yes</td><td>Any error</td></tr><tr><td>Unit tests</td><td>Optional local</td><td>Yes</td><td>Any failure</td></tr><tr><td>Secret scan</td><td>Yes</td><td>Yes</td><td>Any finding</td></tr><tr><td>SAST</td><td>Optional</td><td>Yes</td><td>Critical/High</td></tr><tr><td>SCA</td><td>—</td><td>Yes</td><td>Critical CVE (configurable)</td></tr><tr><td>IaC scan</td><td>—</td><td>Yes (IaC changes)</td><td>High+</td></tr><tr><td>Container scan</td><td>—</td><td>Yes (deploy stage)</td><td>Critical</td></tr><tr><td>OpenAPI lint</td><td>—</td><td>Yes (spec changes)</td><td>Errors</td></tr><tr><td>AI PR review</td><td>—</td><td>Advisory → blocking</td><td>Team policy</td></tr></tbody></table><hr><h2 id="ai-classic-tools-division-of-labor" tabindex="-1">AI + classic tools: division of labor <a class="header-anchor" href="#ai-classic-tools-division-of-labor" aria-label="Permalink to &quot;AI + classic tools: division of labor&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Concern</th><th>Classic tool</th><th>AI review</th></tr></thead><tbody><tr><td>Formatting / style</td><td>Formatter + linter</td><td>Unreliable for consistency</td></tr><tr><td>Known CVE patterns</td><td>SCA, container scan</td><td>May miss new CVEs</td></tr><tr><td>OWASP top 10 patterns</td><td>SAST</td><td>May miss context</td></tr><tr><td>Secret leakage</td><td>gitleaks</td><td><strong>Pitfall:</strong> AI invents keys</td></tr><tr><td>Business logic bugs</td><td>Tests + human review</td><td>AI review helps</td></tr><tr><td>Architecture fit</td><td>ADR + OPA + human</td><td>AI may suggest wrong pattern</td></tr></tbody></table><p><strong>Rule:</strong> Never drop classic validators because AI review is enabled. AI review <strong>stacks on top</strong>, not replaces.</p><hr><h2 id="pitfalls" tabindex="-1">Pitfalls <a class="header-anchor" href="#pitfalls" aria-label="Permalink to &quot;Pitfalls&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pitfall</th><th>Why it hurts</th><th>Mitigation</th></tr></thead><tbody><tr><td><strong>Lint only in CI</strong></td><td>Slow iteration; noisy PRs</td><td>pre-commit + editor</td></tr><tr><td><strong>Different configs per developer</strong></td><td>AI + human code clash</td><td>Single checked-in config</td></tr><tr><td><strong>Warning fatigue</strong></td><td>Real issues ignored</td><td>Fix or disable rule explicitly</td></tr><tr><td><strong>Grandfathering entire repo</strong></td><td>New code clean; old rot remains</td><td>Ratchet or phased fix</td></tr><tr><td><strong>AI bypasses type system</strong></td><td>Runtime errors in prod</td><td>Strict typecheck CI</td></tr><tr><td><strong>No lockfile scan</strong></td><td>CVE in transitive dep</td><td>SCA on every lockfile change</td></tr><tr><td><strong>Secrets in test fixtures</strong></td><td>gitleaks false positives or real leaks</td><td>Synthetic fixtures; allowlist baseline</td></tr><tr><td><strong>Duplicate tools</strong></td><td>ESLint + Biome + Prettier overlap</td><td>Consolidate</td></tr><tr><td><strong>Spec lint missing</strong></td><td>AI OpenAPI invalid</td><td>Spectral on spec PRs</td></tr><tr><td><strong>Container scan only at deploy</strong></td><td>Late surprise</td><td>Scan in CI after build</td></tr></tbody></table><hr><h2 id="suggested-starting-point-minimal-enterprise-set" tabindex="-1">Suggested starting point (minimal enterprise set) <a class="header-anchor" href="#suggested-starting-point-minimal-enterprise-set" aria-label="Permalink to &quot;Suggested starting point (minimal enterprise set)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Tools</th></tr></thead><tbody><tr><td><strong>JS/TS service</strong></td><td>ESLint + Prettier + <code>tsc</code> + Jest/Vitest</td></tr><tr><td><strong>Python service</strong></td><td>Ruff (lint+format) + mypy + pytest</td></tr><tr><td><strong>Go service</strong></td><td>golangci-lint + go test</td></tr><tr><td><strong>All repos</strong></td><td>gitleaks (pre-commit) + Dependabot/Renovate</td></tr><tr><td><strong>CI</strong></td><td>Semgrep + Snyk or Inspector + Checkov/CDK Nag</td></tr><tr><td><strong>Specs</strong></td><td>Spectral + Schemathesis in service CI</td></tr><tr><td><strong>Deploy</strong></td><td>Trivy or ECR scan on image</td></tr></tbody></table><p>Add SonarQube or CodeQL when compliance or scale demands central quality dashboards.</p><hr><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./ai-guardrails-security.html">AI guardrails &amp; security</a> — security policy and AI data handling</li><li><a href="./automated-testing-qa.html">Automated testing &amp; QA</a> — tests vs linters</li><li><a href="./ci-cd-release.html">CI/CD &amp; release</a> — where scans sit in pipeline</li><li><a href="./../sops/SOP-005-pr-review.html">SOP-005 PR review</a> — merge checklist</li></ul>`,82)])])}const m=e(s,[["render",o]]);export{p as __pageData,m as default};
